def load_mock_data() -> list[Property]:
    """Load all mock properties."""
    return MOCK_PROPERTIES

def get_mock_properties_by_district(district: str) -> list[Property]:
    """Filter mock properties by administrative district."""
    d = (district or '').strip().lower()

    def _match(p):
        s = p.scraped_data
        return d in {(s.administrative_district or '').lower(), (s.city or '').lower(), (s.region or '').lower()} and d != ''
    return [p for p in MOCK_PROPERTIES if _match(p)]
